import requests

# Kong Admin API base URL
admin_api_url = "http://localhost:8001"

# Function to create a service
def create_service(name, url):
    response = requests.post(f"{admin_api_url}/services", json={"name": name, "url": url})
    if response.status_code == 201:
        return response.json()
    else:
        print(f"Failed to create service: {response.text}")
        return None

# Function to create a route
def create_route(service_id, paths):
    response = requests.post(f"{admin_api_url}/routes", json={"paths": paths, "service": {"id": service_id}})
    if response.status_code == 201:
        return response.json()
    else:
        print(f"Failed to create route: {response.text}")
        return None

# Function to create an upstream
def create_upstream(name):
    response = requests.post(f"{admin_api_url}/upstreams", json={"name": name})
    if response.status_code == 201:
        return response.json()
    else:
        print(f"Failed to create upstream: {response.text}")
        return None

# Function to add targets to an upstream
def add_targets_to_upstream(upstream_id, targets):
    for target in targets:
        response = requests.post(f"{admin_api_url}/upstreams/{upstream_id}/targets", json={"target": target})
        if response.status_code == 201:
            print(f"Added target {target} to upstream {upstream_id}")
        else:
            print(f"Failed to add target {target}: {response.text}")

# Example usage
if __name__ == "__main__":
    # Create a service
    service = create_service("my-service", "http://example.com")
    if service:
        # Create a route for the service
        route = create_route(service["id"], ["/api"])
        if route:
            # Create an upstream
            upstream = create_upstream("my-upstream")
            if upstream:
                # Add targets to the upstream
                add_targets_to_upstream(upstream["id"], ["10.0.0.1:80", "10.0.0.2:80"])